```class Solution {
public:
    bool canTransform(string start, string result) {
        int n = start.size();
        for (int i = 0; i < n; ++i) {
            if (start[i] != result[i] && start[i] != 'X' && result[i] != 'X') {
                return false;
            }
        }
        int l = 0, r = 0;
        for (int i = 0; i < n; ++i) {
            if (start[i] == 'L') ++l;
            if (result[i] == 'L') ++r;
            if (l < r) return false;
        }
        l = 0, r = 0;
        for (int i = n - 1; i >= 0; --i) {
            if (start[i] == 'R') ++l;
            if (result[i] == 'R') ++r;
            if (l > r) return false;
        }
        return true;
    }
};
